package com.wjx871.population.audit;

import com.wjx871.population.common.ApiResponse;import java.time.LocalDateTime;import lombok.RequiredArgsConstructor;import org.springframework.data.domain.Page;import org.springframework.format.annotation.DateTimeFormat;import org.springframework.security.access.prepost.PreAuthorize;import org.springframework.web.bind.annotation.*;
@RestController@RequestMapping("/api/logs")@RequiredArgsConstructor public class LogQueryController{private final LogQueryService service;
 @GetMapping("/operations")@PreAuthorize("hasAuthority('log:view')") public ApiResponse<Page<LogQueryView>> operations(@RequestParam(required=false)String username,@RequestParam(required=false)String operationType,@RequestParam(required=false)String module,@RequestParam(required=false)String result,@RequestParam(required=false)String ip,@RequestParam(required=false)@DateTimeFormat(iso=DateTimeFormat.ISO.DATE_TIME)LocalDateTime dateFrom,@RequestParam(required=false)@DateTimeFormat(iso=DateTimeFormat.ISO.DATE_TIME)LocalDateTime dateTo,@RequestParam(defaultValue="0")int page,@RequestParam(defaultValue="10")int size){return ApiResponse.ok(service.search(false,username,operationType,module,result,ip,dateFrom,dateTo,page,size));}
 @GetMapping("/logins")@PreAuthorize("hasAuthority('log:view')") public ApiResponse<Page<LogQueryView>> logins(@RequestParam(required=false)String username,@RequestParam(required=false)String result,@RequestParam(required=false)String ip,@RequestParam(required=false)@DateTimeFormat(iso=DateTimeFormat.ISO.DATE_TIME)LocalDateTime dateFrom,@RequestParam(required=false)@DateTimeFormat(iso=DateTimeFormat.ISO.DATE_TIME)LocalDateTime dateTo,@RequestParam(defaultValue="0")int page,@RequestParam(defaultValue="10")int size){return ApiResponse.ok(service.search(true,username,null,null,result,ip,dateFrom,dateTo,page,size));}
 @GetMapping("/operations/{id}")@PreAuthorize("hasAuthority('log:view')") public ApiResponse<LogQueryView> get(@PathVariable Long id){return ApiResponse.ok(service.get(id));}}
